#include <bits/stdc++.h>
using namespace std;
int n;
long long ans;
map<pair<string,string>,int> mp;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        string a,b,t="";
        cin>>a>>b;
        t+=a[0],t+=a[1];
        if(t!=b)
            ans+=mp[make_pair(b,t)];
        mp[make_pair(t,b)]++;
    }
    printf("%lld",ans);
    return 0;
}
